    if (totalDims == 0) {
        return GRAPH_FAILED;
    }
    gert::Shape *y_shape = context->GetOutputShape(0);
    (void)y_shape->SetDimNum(totalDims - 1);
    for (uint32_t i = 0; i < totalDims - 1; ++i) {
        y_shape->SetDim(i, x_shape->GetDim(i));
    }
    return GRAPH_SUCCESS;
}

